from difflib import SequenceMatcher

def lcs_ratio(a,b):
    # use difflib ratio as approximation of normalized LCS
    return SequenceMatcher(None, a, b).ratio()

def token_f1(a,b):
    atoks = a.split()
    btoks = b.split()
    common = Counter(atoks) & Counter(btoks)
    num_common = sum(common.values())
    precision = num_common / len(btoks) if btoks else 0.0
    recall = num_common / len(atoks) if atoks else 0.0
    if precision+recall==0:
        return 0.0
    return 2*precision*recall/(precision+recall)

