# compute lcs_ratio for all ayahs
def best_candidates_by_metric(norm_texts, orig, metric='lcs', topk=10):
    scores = []
    for idx, sid, sname, aid, text, ntext in norm_texts:
        if metric=='lcs':
            score = lcs_ratio(orig, ntext)
        elif metric=='f1':
            score = token_f1(orig, ntext)
        else:
            raise ValueError
        scores.append((score, sid, sname, aid, text, ntext))
    scores.sort(reverse=True)
    return scores[:topk]

